// RWKV World byte-level TRIE tokenizer (NOT BPE) — a faithful port of BlinkDL's
// TRIE_TOKENIZER, mirroring apps/vcpu-tick/src/infer/rwkv-tokenizer.ts. RWKV-7
// uses the World vocab; diagnostic SSM endpoints can serve the model with the
// wrong (Qwen) vocab, so browser-step must encode/decode RWKV tokens
// client-side. Greedy longest-match encode, byte-concat decode.

use anyhow::Result;
use base64::{engine::general_purpose, Engine as _};
use once_cell::sync::OnceCell;
use std::collections::HashMap;

const VOCAB_JSON: &[u8] = include_bytes!("../assets/rwkv-world-vocab.json");

struct TrieNode {
    children: HashMap<u8, usize>,
    id: i64,
}

pub struct RwkvTokenizer {
    nodes: Vec<TrieNode>,
    id_to_bytes: HashMap<u32, Vec<u8>>,
}

#[derive(serde::Deserialize)]
struct VocabFile {
    tokens: HashMap<String, String>,
}

impl RwkvTokenizer {
    fn load() -> Result<Self> {
        let vocab: VocabFile = serde_json::from_slice(VOCAB_JSON)?;
        let mut nodes: Vec<TrieNode> = vec![TrieNode {
            children: HashMap::new(),
            id: -1,
        }];
        let mut id_to_bytes: HashMap<u32, Vec<u8>> = HashMap::new();
        for (id_str, b64) in &vocab.tokens {
            let id: u32 = id_str.parse()?;
            let bytes = general_purpose::STANDARD.decode(b64)?;
            let mut node = 0usize;
            for &b in &bytes {
                let next = match nodes[node].children.get(&b) {
                    Some(&n) => n,
                    None => {
                        let n = nodes.len();
                        nodes.push(TrieNode {
                            children: HashMap::new(),
                            id: -1,
                        });
                        nodes[node].children.insert(b, n);
                        n
                    }
                };
                node = next;
            }
            nodes[node].id = id as i64;
            id_to_bytes.insert(id, bytes);
        }
        // <endoftext> sentinel (id 0) decodes to nothing.
        id_to_bytes.insert(0, Vec::new());
        Ok(Self { nodes, id_to_bytes })
    }

    /// Greedy longest-match over the UTF-8 bytes of `text`.
    pub fn encode(&self, text: &str) -> Vec<u32> {
        let bytes = text.as_bytes();
        let mut out = Vec::new();
        let mut i = 0usize;
        while i < bytes.len() {
            let mut node = 0usize;
            let mut best_id: i64 = -1;
            let mut best_len = 0usize;
            let mut j = i;
            while j < bytes.len() {
                match self.nodes[node].children.get(&bytes[j]) {
                    Some(&next) => {
                        node = next;
                        j += 1;
                        if self.nodes[node].id >= 0 {
                            best_id = self.nodes[node].id;
                            best_len = j - i;
                        }
                    }
                    None => break,
                }
            }
            if best_id < 0 {
                // Every single byte is a token (ids 1..=256 map to bytes 0..=255).
                best_id = bytes[i] as i64 + 1;
                best_len = 1;
            }
            out.push(best_id as u32);
            i += best_len;
        }
        out
    }

    /// Concatenate token bytes and UTF-8 decode (lossy, like the TS decoder).
    pub fn decode(&self, ids: &[u32]) -> String {
        let mut buf: Vec<u8> = Vec::new();
        for &id in ids {
            if let Some(b) = self.id_to_bytes.get(&id) {
                buf.extend_from_slice(b);
            }
        }
        String::from_utf8_lossy(&buf).into_owned()
    }
}

/// Process-wide lazily-built tokenizer (the TRIE build is a one-time ~ms cost).
pub fn rwkv_tokenizer() -> Result<&'static RwkvTokenizer> {
    static TOK: OnceCell<RwkvTokenizer> = OnceCell::new();
    if let Some(t) = TOK.get() {
        return Ok(t);
    }
    let t = RwkvTokenizer::load()?;
    Ok(TOK.get_or_init(|| t))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn paris_roundtrip() {
        let tok = rwkv_tokenizer().unwrap();
        // The sovereign oracle: "The capital of France is" -> these World tokens.
        let ids = tok.encode("The capital of France is");
        assert_eq!(ids, vec![6699, 51128, 4706, 44312, 4600]);
        // token 37138 decodes to " Paris" in the World vocab.
        assert!(tok.decode(&[37138]).to_lowercase().contains("paris"));
    }
}
